class Solution:
    def sort(self, nums: list[int]) -> None:
        def insert_sort(nums, n):
            if n <= 0:
                return
            insert_sort(nums, n - 1)
            last = nums[n - 1]
            j = n - 2
            while j >= 0 and nums[j] > last:
                nums[j + 1] = nums[j]
                j -= 1
            nums[j + 1] = last
        insert_sort(nums, len(nums))

