#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    void sort(vector<int>& nums) {
        insert_sort(nums, nums.size());
    }
    void insert_sort(vector<int>& nums, int n) {
        if (n <= 1) return;
        insert_sort(nums, n - 1);
        int last = nums[n - 1];
        int j = n - 2;
        while (j >= 0 && nums[j] > last) {
            nums[j + 1] = nums[j--];
        }
        nums[j + 1] = last;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int t; cin >> t;
    for (int _ = 0; _ < t; _++) {
        int n; cin >> n;
        vector<int> nums(n);
        for (int i = 0; i < n; i++) cin >> nums[i];
        Solution sol;
        sol.sort(nums);
        cout << n << '\n';
        for (int i = 0; i < n; i++) {
            cout << nums[i] << (i == n - 1 ? '\n' : ' ');
        }
    }
    return 0;
}
